    "testedConcept": "Parkinson disease — dopamine deficiency in substantia nigra and levodopa-carbidopa mechanism",
    "weakSpotCategory": "Movement Disorder Pharmacology",
    "usmleContentArea": "Nervous System & Special Senses",
    "usmleSubdomain": "Parkinson Disease",
